MERGE /*+ NOAPPEND PARALLEL (mg, 16)  */ INTO AGG_DD_F_R4G_ADJL mg USING (SELECT /*+ PARALLEL (facts, 16)  */:1  as report_date_time, :2  as year, :3  as month, :4  as week_of_year, :5  as day_of_month, "facts".entity_key as entity_key, MAX("facts".AA_r4g_enodeb_geography_key) KEEP (DENSE_RANK FIRST ORDER BY "facts".time_key desc) as AA_r4g_enodeb_geography_key, MAX("facts".AA_r4g_site_add_info_key) KEEP (DENSE_RANK FIRST ORDER BY "facts".time_key desc) as AA_r4g_site_add_info_key, MAX("facts".AA_r4g_cell_operator_key) KEEP (DENSE_RANK FIRST ORDER BY "facts".time_key desc) as AA_r4g_cell_operator_key, MAX("facts".AA_r4g_cell_info_key) KEEP (DENSE_RANK FIRST ORDER BY "facts".time_key desc) as AA_r4g_cell_info_key, MAX("facts".AA_r4g_cell_radio_key) KEEP (DENSE_RANK FIRST ORDER BY "facts".time_key desc) as AA_r4g_cell_radio_key, MAX("facts".AA_r4g_enodeb_coordinates_key) KEEP (DENSE_RANK FIRST ORDER BY "facts".time_key desc) as AA_r4g_enodeb_coordinates_key, MAX("facts".AA_r4g_municipio_add_info_key) KEEP (DENSE_RANK FIRST ORDER BY "facts".time_key desc) as AA_r4g_municipio_add_info_key, MAX("facts".AA_r4g_cell_coverage_key) KEEP (DENSE_RANK FIRST ORDER BY "facts".time_key desc) as AA_r4g_cell_coverage_key, MAX("facts".AA_r4g_cell_areacode_key) KEEP (DENSE_RANK FIRST ORDER BY "facts".time_key desc) as AA_r4g_cell_areacode_key, SUM("facts".M3154012) as SUM_M3154012, SYSDATE as INSERT_DATE, SYSDATE as UPDATE_DATE FROM F_R4G_ADJL "facts" WHERE ("facts".time_key >= :6  AND "facts".time_key < :7 ) GROUP BY "facts".entity_key) sl on (mg.report_date_time = sl.report_date_time and mg.year = sl.year and mg.month = sl.month and mg.week_of_year = sl.week_of_year and mg.day_of_month = sl.day_of_month and mg.entity_key = sl.entity_key ) when matched then update set AA_r4g_enodeb_geography_key = sl.AA_r4g_enodeb_geography_key, AA_r4g_site_add_info_key = sl.AA_r4g_site_add_info_key, AA_r4g_cell_operator_key = sl.AA_r4g_cell_operator_key, AA_r4g_cell_info_key = sl.AA_r4g_cell_info_key, AA_r4g_cell_radio_key = sl.AA_r4g_cell_radio_key, AA_r4g_enodeb_coordinates_key = sl.AA_r4g_enodeb_coordinates_key, AA_r4g_municipio_add_info_key = sl.AA_r4g_municipio_add_info_key, AA_r4g_cell_coverage_key = sl.AA_r4g_cell_coverage_key, AA_r4g_cell_areacode_key = sl.AA_r4g_cell_areacode_key, SUM_M3154012 = sl.SUM_M3154012, UPDATE_DATE = sl.UPDATE_DATE when not matched then insert (mg.report_date_time, mg.year, mg.month, mg.week_of_year, mg.day_of_month, mg.entity_key, mg.AA_r4g_enodeb_geography_key, mg.AA_r4g_site_add_info_key, mg.AA_r4g_cell_operator_key, mg.AA_r4g_cell_info_key, mg.AA_r4g_cell_radio_key, mg.AA_r4g_enodeb_coordinates_key, mg.AA_r4g_municipio_add_info_key, mg.AA_r4g_cell_coverage_key, mg.AA_r4g_cell_areacode_key, mg.SUM_M3154012, mg.INSERT_DATE, mg.UPDATE_DATE ) VALUES ( sl.report_date_time, sl.year, sl.month, sl.week_of_year, sl.day_of_month, sl.entity_key, sl.AA_r4g_enodeb_geography_key, sl.AA_r4g_site_add_info_key, sl.AA_r4g_cell_operator_key, sl.AA_r4g_cell_info_key, sl.AA_r4g_cell_radio_key, sl.AA_r4g_enodeb_coordinates_key, sl.AA_r4g_municipio_add_info_key, sl.AA_r4g_cell_coverage_key, sl.AA_r4g_cell_areacode_key, sl.SUM_M3154012, sl.INSERT_DATE, sl.UPDATE_DATE)